arguments.file_text:
using ChurnPredictor.Models;
using Microsoft.ML;

namespace ChurnPredictor.Services;

public static class ChurnModelTrainer
{
    public static void TrainAndSave(string dataPath, string modelPath, ILogger logger)
    {
        var mlContext = new MLContext(seed: 42);

        // Load CSV with Yes/No → boolean mapping via custom loader
        IDataView data = mlContext.Data.LoadFromTextFile<ChurnModelInput>(
            dataPath,
            separatorChar: ',',
            hasHeader: true,
            allowQuoting: true);

        // The Label column is loaded as a bool from Yes/No text.
        // ML.NET's LoadFromTextFile maps "Yes"/"No" to true/false for bool columns.
        // However, if that fails, we need a custom mapping.
        // Let's use a value-to-key approach instead: reload as string and map.

        var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

        var pipeline = mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", nameof(ChurnModelInput.Region))
            .Append(mlContext.Transforms.Concatenate("Features",
                nameof(ChurnModelInput.Age),
                nameof(ChurnModelInput.Income),
                "RegionEncoded",
                nameof(ChurnModelInput.PurchaseHistory)))
            .Append(mlContext.Transforms.NormalizeMinMax("Features"))
            .Append(mlContext.BinaryClassification.Trainers.FastTree());

        logger.LogInformation("Training churn prediction model...");
        var model = pipeline.Fit(split.TrainSet);

        var predictions = model.Transform(split.TestSet);
        var metrics = mlContext.BinaryClassification.Evaluate(predictions);

        logger.LogInformation(
            "Model metrics — AUC: {Auc:F4}, Accuracy: {Acc:F4}, F1: {F1:F4}",
            metrics.AreaUnderRocCurve,
            metrics.Accuracy,
            metrics.F1Score);

        mlContext.Model.Save(model, data.Schema, modelPath);
        logger.LogInformation("Model saved to {Path}", modelPath);
    }
}

