using ChurnPredictor.Models;
using Microsoft.ML;

namespace ChurnPredictor.Services;

public static class ChurnModelTrainer
{
    public static void TrainAndSave(string dataPath, string modelPath, ILogger logger)
    {
        var mlContext = new MLContext(seed: 42);

        IDataView data = mlContext.Data.LoadFromTextFile<ChurnModelInput>(
            dataPath,
            separatorChar: ',',
            hasHeader: true,
            allowQuoting: true);

        var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

        // Map "Yes"/"No" string to boolean Label column, then build features.
        var pipeline = mlContext.Transforms.Conversion.MapValue(
                "Label",
                new[] { new KeyValuePair<string, bool>("Yes", true), new KeyValuePair<string, bool>("No", false) },
                inputColumnName: nameof(ChurnModelInput.Churned))
            .Append(mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", nameof(ChurnModelInput.Region)))
            .Append(mlContext.Transforms.Concatenate("Features",
                nameof(ChurnModelInput.Age),
                nameof(ChurnModelInput.Income),
                "RegionEncoded",
                nameof(ChurnModelInput.PurchaseHistory)))
            .Append(mlContext.Transforms.NormalizeMinMax("Features"))
            .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression());

        logger.LogInformation("Training churn prediction model...");
        var model = pipeline.Fit(split.TrainSet);

        var predictions = model.Transform(split.TestSet);
        var metrics = mlContext.BinaryClassification.Evaluate(predictions);

        logger.LogInformation(
            "Model metrics — AUC: {Auc:F4}, Accuracy: {Acc:F4}, F1: {F1:F4}",
            metrics.AreaUnderRocCurve,
            metrics.Accuracy,
            metrics.F1Score);

        mlContext.Model.Save(model, data.Schema, modelPath);
        logger.LogInformation("Model saved to {Path}", modelPath);
    }
}

