using ChurnPredictor.Models;
using ChurnPredictor.Services;
using Microsoft.Extensions.ML;

var builder = WebApplication.CreateBuilder(args);

var dataPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "customers.csv");
var modelPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "churn-model.zip");

// Train the model at startup if it doesn't exist yet.
if (!File.Exists(modelPath))
{
    using var loggerFactory = LoggerFactory.Create(b => b.AddConsole());
    var logger = loggerFactory.CreateLogger("ModelTraining");
    ChurnModelTrainer.TrainAndSave(dataPath, modelPath, logger);
}

// Thread-safe pooled prediction engine for ASP.NET Core.
builder.Services.AddPredictionEnginePool<ChurnModelInput, ChurnModelOutput>()
    .FromFile(modelPath);

var app = builder.Build();

app.MapGet("/", () => "Churn Predictor API — POST /predict with { age, income, region, purchaseHistory }");

app.MapPost("/predict", (ChurnPredictionRequest req, PredictionEnginePool<ChurnModelInput, ChurnModelOutput> pool) =>
{
    var input = new ChurnModelInput
    {
        Age = req.Age,
        Income = req.Income,
        Region = req.Region,
        PurchaseHistory = req.PurchaseHistory
    };

    var prediction = pool.Predict(input);

    return Results.Ok(new
    {
        WillChurn = prediction.PredictedLabel,
        Probability = prediction.Probability
    });
});

app.Run();

